const fs = require('fs');
const key = ($json.body && $json.body.key) || ($json.key) || '';
const dbPath = '/home/lucy-ubuntu/Escritorio/NIN/memoria/agente_memoria.db'.replace('agente_memoria.db', 'memory_store.json');
try {
  let store = {};
  if (fs.existsSync(dbPath)) store = JSON.parse(fs.readFileSync(dbPath, 'utf8'));
  if (store[key]) {
    store[key].score = (store[key].score || 1) + 0.5;
    store[key].last_applied = new Date().toISOString();
    fs.writeFileSync(dbPath, JSON.stringify(store, null, 2));
    return [{ json: { output: '✅ Memoria aplicada: ' + key + '\n' + store[key].value } }];
  }
  return [{ json: { output: '🔍 No se encontró: ' + key } }];
} catch(e) {
  return [{ json: { output: '❌ Error: ' + e.message } }];
}
